CREATE OR REPLACE VIEW vm_com_m_receipt_item (membership_no, receipt_no, seq_no, description, period, principal_amount, interest_amount, item_amount, balance, sort_order, group_item) AS SELECT sc_com_m_receipt.membership_no,
       sc_com_m_receipt_item.receipt_no,
       sc_com_m_receipt_item.seq_no, 
       
         sc_com_m_receipt_item.description, 
         sc_com_m_receipt_item.period,
         sc_com_m_receipt_item.principal_amount,   
         sc_com_m_receipt_item.interest_amount,   
         sc_com_m_receipt_item.item_amount,   
         sc_com_m_receipt_item.balance,   
         
         sc_com_m_ucf_receipt_item_type.sort_order,
         sc_com_m_ucf_receipt_item_type.group_item
    FROM sc_com_m_receipt ,
         sc_com_m_receipt_item ,   
         sc_com_m_ucf_receipt_item_type ,
         sc_mem_m_membership_registered
         ,sc_acc_m_account_year
   WHERE 1=1
   and  sc_com_m_receipt.receipt_no = sc_com_m_receipt_item.receipt_no 
   and  sc_com_m_receipt_item.item_type_id = sc_com_m_ucf_receipt_item_type.item_type_id 
   and	sc_com_m_receipt_item.item_amount > 0
   and  sc_mem_m_membership_registered.membership_no = sc_com_m_receipt.membership_no
   and  sc_mem_m_membership_registered.member_status_code = '0'
   and  sc_com_m_receipt.receipt_status = '0' 

   and  sc_acc_m_account_year.account_year = 2020
   and  sc_com_m_receipt.receipt_date >= sc_acc_m_account_year.beginning_of_account;

